(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["sintesis"],{"15a3":function(e,a,i){"use strict";i.r(a);var s=function(){var e=this,a=e._self._c;return a("div",{staticClass:"curso-main-container pb-3"},[a("BannerInterno",{attrs:{icono:"fas fa-sitemap",titulo:"Síntesis"}}),a("div",{staticClass:"container tarjeta tarjeta--blanca p-4 p-md-5"},[a("p",[e._v("La producción limpia y la reconversión sostenible constituyen estrategias clave para transformar los sistemas agropecuarios tradicionales en modelos más eficientes, responsables y competitivos. Su implementación integra prevención de la contaminación, uso eficiente de recursos y gestión ambiental, reduciendo impactos sobre suelo, agua y biodiversidad, mientras fortalece las capacidades técnicas y organizativas del sector rural. Este enfoque incorpora criterios ambientales, sociales y económicos en la planificación productiva, promueve la resiliencia frente al cambio climático y las exigencias del mercado, y se apoya en indicadores que permiten evaluar eficiencia, viabilidad y sostenibilidad. En conjunto, impulsa el desarrollo rural sostenible, la competitividad y una cultura de responsabilidad ambiental orientada a la mejora continua. ")]),a("div",{staticClass:"row justify-content-center"},[e._m(0),a("div",{staticClass:"col-auto"},[a("a",{staticClass:"anexo mb-5",attrs:{href:e.obtenerLink("/downloads/Sintesis.pdf"),target:"_blank"}},[e._m(1),e._m(2)])])])])],1)},o=[function(){var e=this,a=e._self._c;return a("div",{staticClass:"col-lg-12 mb-5 bgs p-4 brad"},[a("figure",[a("img",{attrs:{src:i("cc8e"),alt:"El mapa conceptual titulado “Producción limpia y reconversión sostenible en el sector rural” organiza el contenido en cuatro ejes principales: primero, producción agropecuaria y medio ambiente, que aborda conceptos principales, la problemática ambiental global y el impacto de la actividad agrícola y pecuaria sobre los recursos naturales, la producción limpia y reconversión productiva, incluyendo los principios de la producción limpia en el sector agropecuario, las alternativas de producción más limpia como la agricultura orgánica, la reconversión agrícola y ganadera, y los modelos productivos sostenibles como policultivos, sistemas silvopastoriles y agroforestales; el segundo, sostenibilidad y desarrollo sostenible, que comprende el concepto de sostenibilidad, el desarrollo sostenible en el contexto rural, los Objetivos de Desarrollo Sostenible (ODS) y su relación con el sector agropecuario, así como los indicadores de sostenibilidad rural; el tercer eje, teoría general de sistemas, que integra definiciones, clases de sistemas, componentes, características, modelos sistémicos aplicados a la agroecología y el agroecosistema como sistema complejo; y finalmente, aportes de las comunidades indígenas en el manejo de la biodiversidad, que contempla la cosmovisión indígena y territorio, los sistemas tradicionales de producción, la conservación de semillas nativas, el manejo ancestral del agua y del suelo, la gobernanza territorial y biodiversidad, y el diálogo de saberes."}})])])},function(){var e=this,a=e._self._c;return a("div",{staticClass:"anexo__icono"},[a("img",{attrs:{src:i("abd8")}})])},function(){var e=this,a=e._self._c;return a("div",{staticClass:"anexo__texto"},[a("p",[e._v("Anexo. Síntesis")])])}],n={name:"Sintesis",data:()=>({}),mounted(){this.$nextTick(()=>{this.$aosRefresh()})},updated(){this.$aosRefresh()}},t=n,r=i("2877"),c=Object(r["a"])(t,s,o,!1,null,null,null);a["default"]=c.exports},abd8:function(e,a,i){e.exports=i.p+"img/icono-pdf.82f139cb.svg"},cc8e:function(e,a,i){e.exports=i.p+"img/sintesis.8b064caa.svg"}}]);
